def validate(args, output):
    nums = args[0]
    n = len(nums)
    if not isinstance(output, list):
        return False
    from collections import Counter
    import math
    target = Counter(nums)
    seen = set()
    for perm in output:
        if not isinstance(perm, list) or len(perm) != n:
            return False
        if Counter(perm) != target:
            return False
        key = tuple(perm)
        if key in seen:
            return False
        seen.add(key)
    distinct = math.factorial(n)
    for c in target.values():
        distinct //= math.factorial(c)
    return len(seen) == distinct

