function validate(args, output) {
    const nums = args[0];
    const n = nums.length;
    if (!Array.isArray(output)) return false;
    function counts(arr) {
        const m = new Map();
        for (const v of arr) m.set(v, (m.get(v) || 0) + 1);
        return m;
    }
    function sameCounts(a, b) {
        if (a.size !== b.size) return false;
        for (const [k, v] of a) if (b.get(k) !== v) return false;
        return true;
    }
    const target = counts(nums);
    const seen = new Set();
    for (const perm of output) {
        if (!Array.isArray(perm) || perm.length !== n) return false;
        if (!sameCounts(counts(perm), target)) return false;
        const key = perm.join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    let distinct = 1;
    for (let i = 2; i <= n; i++) distinct *= i;
    for (const c of target.values()) {
        let f = 1;
        for (let i = 2; i <= c; i++) f *= i;
        distinct /= f;
    }
    return seen.size === distinct;
}

