class Solution:
    def permuteUnique(self, nums):
        nums = sorted(nums)
        res = []
        used = [False] * len(nums)
        cur = []
        def back():
            if len(cur) == len(nums):
                res.append(cur[:])
                return
            for i in range(len(nums)):
                if used[i]:
                    continue
                if i > 0 and nums[i] == nums[i - 1] and not used[i - 1]:
                    continue
                used[i] = True
                cur.append(nums[i])
                back()
                cur.pop()
                used[i] = False
        back()
        res.sort()
        return res

